it("should not highlight for days after the end date", () => {
  const { day, startDate, endDate } = createDateRange(-1, 1);
  const selectingDate = addDays(endDate, 1);
  const container = renderDay(day, {
    startDate,
    endDate,
    selectingDate,
    selectsRange: true,
  });
  expect(
    container
      .querySelector(".react-datepicker__day")
      ?.classList.contains(rangeDayClassName),
  ).toBe(false);
});

it("should not highlight if there is no end date selected", () => {
  const startDate = newDate();
  const selectingDate = subDays(startDate, 1);
  const container = renderDay(selectingDate, {
    startDate,
    selectingDate,
    selectsRange: true,
  });
  expect(
    container
      .querySelector(".react-datepicker__day")
      ?.classList.contains(rangeDayClassName),
    ).toBe(false);
});

it("should not highlight days outside the displayed month", () => {
  const startDate = newDate("2021-01-15");
  const selectingDate = newDate("2021-01-20");
  const outsideMonthDay = newDate("2020-12-31");
  const container = renderDay(outsideMonthDay, {
    month: 0,
    startDate,
    selectingDate,
    selectsRange: true,
  });

  expect(
    container
      .querySelector(".react-datepicker__day")
      ?.classList.contains(rangeDayClassName),
  ).toBe(false);
});

